import{_ as t,o,c as n,a3 as r}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"26. Fixed Term Employment","description":"","frontmatter":{"title":"26. Fixed Term Employment","eba":"Medical Scientists, Pharm & Psych 2021-2025","topics":["employment","preliminary"]},"headers":[],"relativePath":"ebas/mspp/employment/26-fixed-term-employment.md","filePath":"ebas/mspp/employment/26-fixed-term-employment.md"}'),i={name:"ebas/mspp/employment/26-fixed-term-employment.md"};function a(s,e,m,p,l,c){return o(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="_26-fixed-term-employment" tabindex="-1">26. Fixed Term Employment <a class="header-anchor" href="#_26-fixed-term-employment" aria-label="Permalink to &quot;26. Fixed Term Employment&quot;">​</a></h1><p><strong>a.</strong> The Employer will give preference to ongoing forms of employment over casual and fixed term arrangements wherever possible. Fixed term employment will only be used for &quot;true fixed term arrangements&quot;.</p><p><strong>b.</strong> A fixed term Employee is an Employee employed for a specified period of time which period is known at the commencement of the contract, or employed for a specified task such as a project or replacement of an absent Employee,</p><p>3453-8976-3100v1PART 4: EMPLOYMENT RELATIONSHIP AND RELATED ARRANGEMENTS</p><p>where the contract contains clear terms as to when a contract is at an end such as starting and finishing dates.</p><p><strong>c.</strong> In the normal course, a fixed term contract will not exceed 12 months save that this does not prevent a subsequent fixed term contract being offered where it complies with this clause 26.</p><p><strong>d.</strong> Subject to clause e, fixed term employment will not be used to fill an ongoing position.</p><p><strong>e.</strong> Examples of where fixed term employment may be appropriate include but are not limited to:</p><p><strong>(i)</strong> Employment positions to support qualification and / or registration;</p><p><strong>(ii)</strong> Long term absence backfill (including for WorkCover), where the duration of the absence is known;</p><p><strong>(iii)</strong> Special Projects;</p><p><strong>(iv)</strong> Positions related to identifiable funding to the Employer not being funding that is part of an operating grant from government; and</p><p><strong>(v)</strong> Backfill including for extended leave (such as Parental Leave and Long Service Leave) and to support flexible working arrangements. Note: In this context, backfill to support flexible working arrangements does not refer to the Employee on the flexible working arrangement, but instead to an arrangement to work hours that arise from a flexible work arrangement that includes a temporary reduction in hours.</p><p><strong>26.2</strong> Fixed Term Employment Conversion</p><p><strong>a.</strong> Where a fixed term Employee is offered a subsequent fixed term contract (including an extension of the existing fixed term contract), the Employer and the Employee recognise that the Employee may be more properly classified as an on-going rather than fixed term Employee.</p><p><strong>b.</strong> The Employee will not be considered to be more properly classified as an on- going rather than fixed term Employee where the fixed term engagement continues to be genuine, such as replacing an Employee absence (including but not limited to parental leave, long service leave, workers compensation, personal leave) or flexible work arrangement.</p><p><strong>c.</strong> Either the Employer or the Employee has the right to request in writing the conversion to on-going employment and that request will not be unreasonably refused by either party.</p><p><strong>d.</strong> In the event of a dispute over a request conversion from fixed term to on-going employment, a further fixed term contract will not prejudice either party.</p><p><strong>e.</strong> Where such a conversion occurs, the Employee will be provided with a Letter of Appointment setting out the revised employment arrangements, including any period/s of fixed term employment with the Employer, which shall count as the Employee’s service.</p><p><strong>f.</strong> Where an Employee continues to work once a fixed term contract has expired, the Employee will be converted to on-going employment from the end date of the fixed term contract.</p><p>Plain language terms: contract, fixed-term.</p>',21)])])}const h=t(i,[["render",a]]);export{g as __pageData,h as default};
